use NFSDB; CREATE TABLE Departments (    DeptID INT PRIMARY KEY,    DeptName VARCHAR(50),    Location VARCHAR(50));INSERT INTO Departments VALUES(1, 'IT', 'Delhi'),(2, 'HR', 'Mumbai'),(3, 'Finance', 'Delhi');SELECT * FROm Departments;SELECT * FROm Employees;-- basic Sub Query based on above tables -- Show employees who are earning more than average salary SELECT FirstName, Salary FROM dbo.EmployeesWHERE Salary > (SELECT AVG(Salary) FROM dbo.Employees);-- Subquery with In operator-- Employees who are from Delhi SELECT FIRSTName, Department FROM dbo.EmployeesWHERE Department IN (SELECT DeptName FROM dbo.Departments WHERE Location = 'Delhi');SELECT FirstName, Salary, Department FROM dbo.Employees EWHERE Salary >(SELECT AVG(Salary)FROM dbo.EmployeesWHERE Department = E.Department);